Use a HashMap where key = (i − j) and value = first element of that diagonal.
Compare remaining elements in same diagonal.
import java.util.*;
class Main{
public static void main(String[] args){
Scanner sc=new Scanner(System.in);
int m=sc.nextInt();
int n=sc.nextInt();
int[][] mat=new int[m][n];
for(int i=0;i<m;i++){
for(int j=0;j<n;j++){
mat[i][j]=sc.nextInt();
}
}
boolean flag=true;
HashMap<Integer,Integer> map=new HashMap<>();
for(int i=0;i<m;i++){
for(int j=0;j<n;j++){
int key=i-j;
if(!map.containsKey(key)){
map.put(key,mat[i][j]);
}else{
if(map.get(key)!=mat[i][j]){
flag=false;
}
}
}
}
int result=1;
if(flag){
result=0;
for(int j=0;j<n;j++){
result+=mat[0][j];
}
}else{
for(int j=0;j<n;j++){
result*=mat[0][j];
}
}
System.out.println(result);
}
}

Use HashMap<StockID, Quantity> for fast lookup.
import java.util.*;
class Main{
public static void main(String[] args){
Scanner sc=new Scanner(System.in);
int n=sc.nextInt();
HashMap<Integer,Integer> map=new HashMap<>();
for(int i=0;i<n;i++){
int id=sc.nextInt();
int qty=sc.nextInt();
map.put(id,qty);
}
int q=sc.nextInt();
int score=0;
for(int i=0;i<q;i++){
int id=sc.nextInt();
if(map.containsKey(id)){
int qty=map.get(id);
if(qty==2) score+=3;
else if(qty==1) score+=2;
else if(qty==0) score-=2;
}else{
score-=6;
}
}
System.out.println(score);
}
}
